/**
 * ALTCHA Widget Loader Shim
 * Self-hosted loader that ensures the ALTCHA web component is available.
 * Falls back to CDN sources if the local bundle is not present.
 *
 * Source: https://github.com/altcha-org/altcha (MIT License)
 * Version: 2.x
 */
(function () {
  'use strict';

  if (customElements.get('altcha-widget')) {
    document.dispatchEvent(new CustomEvent('altcha-loaded'));
    return;
  }

  var sources = [
    'https://cdn.jsdelivr.net/npm/altcha@2/dist/altcha.min.js',
    'https://unpkg.com/altcha@2/dist/altcha.min.js',
  ];

  var loaded = false;

  function tryLoad(index) {
    if (loaded || index >= sources.length) {
      if (!loaded) {
        console.error(
          '[ALTCHA] Failed to load widget from all sources. CAPTCHA will not be available.'
        );
      }
      return;
    }

    var script = document.createElement('script');
    script.src = sources[index];
    script.type = 'module';
    script.onload = function () {
      loaded = true;
      if (customElements.get('altcha-widget')) {
        document.dispatchEvent(new CustomEvent('altcha-loaded'));
      } else {
        customElements.whenDefined('altcha-widget').then(function () {
          document.dispatchEvent(new CustomEvent('altcha-loaded'));
        });
      }
    };
    script.onerror = function () {
      console.warn('[ALTCHA] Failed to load from ' + sources[index] + ', trying next source\u2026');
      script.remove();
      tryLoad(index + 1);
    };
    document.head.appendChild(script);
  }

  tryLoad(0);
})();
